    cache(int32(9923)) = 'the 1223rd prime. 16 hollow integers precede it. then suddenly real. closer to infinity than to any pitch a human has named.';
    cache(int32(9929)) = 'the 1224th prime. a twin prime. it does not travel alone. nearly at the edge. the primes here are enormous and cold.';
    cache(int32(9931)) = 'the 1225th prime. paired. another prime within reach. approaching ten thousand. infinity is visible from here.';
    cache(int32(9941)) = 'the 1226th prime. 10 steps of silence before arrival. isolated. the strangeness is absolute. every interval is alien.';
    cache(int32(9949)) = 'the 1227th prime. preceded by 8 empty integers. a void then a prime. so far from the fundamental that the concept of tuning is abstract.';
    cache(int32(9967)) = 'the 1228th prime. the gap before it is 18. patience before presence. the lattice has no edges but this prime is near one.';
    cache(int32(9973)) = 'the 1229th prime. acoustic meaning has evaporated. only number remains.';
  end

  key = int32(p);
  if cache.isKey(key)
    desc = cache(key);
  elseif p <= 1
    desc = 'not a prime.';
  elseif p > 10000
    desc = sprintf('prime %d. beyond ten thousand. the ominous has become the infinite.', p);
  else
    desc = sprintf('prime %d. composite or out of range.', p);
  end
end
